USE rbe;

-- ============================================================
-- RBE · Demo Abril 2026 — CORREGIDO
-- Ejecutar DESPUÉS del script base limpio
-- ============================================================

SET FOREIGN_KEY_CHECKS = 0;
DELETE FROM ticket        WHERE codigo  >= 215;
DELETE FROM pago          WHERE numero  >= 33;
DELETE FROM viaje_asiento WHERE viaje   >= 68;
DELETE FROM viaje         WHERE numero  >= 68;
ALTER TABLE viaje   AUTO_INCREMENT = 1000;
ALTER TABLE pago    AUTO_INCREMENT = 2000;
ALTER TABLE ticket  AUTO_INCREMENT = 5000;
SET FOREIGN_KEY_CHECKS = 1;

