-- ============================================================
-- MARCAR ASIENTOS OCUPADOS según tickets insertados
-- ============================================================

UPDATE viaje_asiento va
JOIN ticket t ON t.asiento = va.asiento AND t.viaje = va.viaje
SET va.ocupado = 1
WHERE va.viaje BETWEEN 1000 AND 1176;

-- ============================================================
-- VERIFICACIÓN
-- ============================================================

SELECT 'viajes abril'  AS info, COUNT(*) AS n FROM viaje  WHERE numero BETWEEN 1000 AND 1176;
SELECT 'finalizados'   AS info, COUNT(*) AS n FROM viaje  WHERE numero BETWEEN 1000 AND 1176 AND estado=3;
SELECT 'en ruta'       AS info, COUNT(*) AS n FROM viaje  WHERE numero BETWEEN 1000 AND 1176 AND estado=2;
SELECT 'disponibles'   AS info, COUNT(*) AS n FROM viaje  WHERE numero BETWEEN 1000 AND 1176 AND estado=1;
SELECT 'cancelados'    AS info, COUNT(*) AS n FROM viaje  WHERE numero BETWEEN 1000 AND 1176 AND estado=4;
SELECT 'retrasados'    AS info, COUNT(*) AS n FROM viaje  WHERE numero BETWEEN 1000 AND 1176 AND estado=5;
SELECT 'pagos abril'   AS info, COUNT(*) AS n FROM pago   WHERE numero BETWEEN 2000 AND 2089;
SELECT 'tickets abril' AS info, COUNT(*) AS n FROM ticket WHERE codigo BETWEEN 5000 AND 5898;
SELECT 'recaudado'     AS info, CONCAT('$',FORMAT(SUM(monto),2)) AS n FROM pago WHERE numero BETWEEN 2000 AND 2089;